// ── PowerPlug brand intelligence (Claude Code rebuild 2026-04-15) ──
const html = $input.first().json.data || $input.first().json.body || '';

// Logo URL (verified on live site; fallback to known canonical path).
const logoMatch = html.match(/(https?:\/\/powerplug\.ai\/wp-content\/uploads\/\d{4}\/\d{2}\/powerplug-logo\.(?:png|svg|webp))/i);
const logoUrl = logoMatch ? logoMatch[1] : 'https://powerplug.ai/wp-content/uploads/2022/06/powerplug-logo.png';

// Contact URL (discovered or canonical).
const contactMatch = html.match(/href=[\"']((?:https?:\/\/powerplug\.ai)?\/contact-us[^\"']*)[\"']/i);
const contactUrl = contactMatch
  ? (contactMatch[1].startsWith('http') ? contactMatch[1] : `https://powerplug.ai${contactMatch[1]}`)
  : 'https://powerplug.ai/contact-us';

return [{
  json: {
    brand: {
      name: 'PowerPlug Ltd.',
      domain: 'powerplug.ai',
      homeUrl: 'https://powerplug.ai',
      contactUrl: contactUrl,
      logoUrl: logoUrl,
      phone: '+1-646-751-7797',
      phoneHref: 'tel:+16467517797',
      email: 'info@powerplug.ai',
      address: '7 HaArad Street, Tel Aviv 6971060, Israel',
      colors: {
        navyPrimary: '#151d3f',
        navySection: '#202953',
        navyDeep:    '#131b3b',
        greenAccent: '#8bc540',
        greenLight:  '#f7fbf3',
        surface:     '#f5f9fc',
        card:        '#ffffff',
        textPrimary: '#1a2540',
        textMuted:   '#475569',
        border:      '#e2e5ea'
      },
      socialHover: {
        facebook: '#1877F2',
        twitter:  '#000000',
        linkedin: '#0A66C2'
      },
      social: {
        facebook: 'https://www.facebook.com/PowerPlugLtd/',
        twitter:  'https://twitter.com/PowerPlugLtd',
        linkedin: 'https://www.linkedin.com/company/powerplug-ltd'
      },
      internalUrls: [
        'https://powerplug.ai/our-platform',
        'https://powerplug.ai/wakeup-technology',
        'https://powerplug.ai/case-studies',
        'https://powerplug.ai/who-we-are',
        'https://powerplug.ai/downloads',
        'https://powerplug.ai/category/powerplug-blog',
        'https://powerplug.ai/contact-us'
      ],
      externalReferences: [
        'https://www.energystar.gov/products/office_equipment/computers',
        'https://www.iea.org/reports/digitalisation-and-energy',
        'https://www.gartner.com/en/information-technology/insights/sustainability',
        'https://learn.microsoft.com/en-us/windows/win32/power/power-management-portal'
      ],
      verifiedCaseStudies: [
        { name: 'Clalit Health Services', metric: '45,000+ PCs', outcome: '$1.2M annual savings' },
        { name: 'Rambam Healthcare Campus', metric: '2,000+ PCs', outcome: 'ROI under 4 months' },
        { name: 'Ben Gurion University', metric: '20,000+ student PCs', outcome: 'green-campus initiative' }
      ],
      fontStack: "'Montserrat','Segoe UI',-apple-system,BlinkMacSystemFont,Roboto,Arial,sans-serif"
    },
    articleConfig: {
      direction: 'ltr',
      lang: 'en',
      maxWidth: '820px',
      baseFontSize: '17px',
      bodyLineHeight: '1.75'
    }
  }
}];

// ── Merge webhook input with brand + system prompt ──
const webhook = $('Webhook Trigger').first().json.body || $('Webhook Trigger').first().json;
const brand = $('Extract Brand Intelligence').first().json.brand;
const articleConfig = $('Extract Brand Intelligence').first().json.articleConfig;
const systemPrompt = $('Load System Prompt').first().json.systemPrompt;

const topic         = webhook.topic || 'Enterprise PC Power Management';
const targetKeyword = webhook.targetKeyword || topic;
const wordCount     = webhook.wordCount || 2800;
const sections      = webhook.sections || 10;
const faqCount      = webhook.faqCount || 7;
const includeImages = webhook.includeImages !== false;
const imageUrls     = Array.isArray(webhook.imageUrls) ? webhook.imageUrls : [];

const userPrompt = `Write a complete enterprise-grade HTML article for PowerPlug.ai about: ${topic}\nPrimary keyword: ${targetKeyword}\nTarget body length: ~${wordCount} words\nNumber of H2 body sections: ${sections}\nNumber of FAQ items: ${faqCount}\n${includeImages ? `You may use these image URLs where relevant (omit rather than include a broken image):\n${imageUrls.join('\n') || '- none supplied — omit images or use a single decorative figure at most'}` : 'Do not include any <img> tags in the body.'}\n\nEnforce every rule from the system message. Return ONLY the article HTML.`;

return [{
  json: {
    systemPrompt,
    userPrompt,
    brand,
    articleConfig,
    content: { topic, targetKeyword, wordCount, sections, faqCount, includeImages, imageUrls }
  }
}];

// ── Post-generation validation (Claude Code rebuild 2026-04-15) ──
const brand = $('Extract Brand Intelligence').first().json.brand;
let html = $input.first().json.message?.content
        || $input.first().json.text
        || $input.first().json.choices?.[0]?.message?.content
        || '';
html = html.replace(/^```html?\n?/i, '').replace(/\n?```\s*$/i, '').trim();

const errors = [];
const warnings = [];

// Rule 14 — exactly one H1
const h1Count = (html.match(/<h1[\s>]/gi) || []).length;
if (h1Count !== 1) errors.push(`Rule 14: expected exactly 1 <h1>, found ${h1Count}`);

// Rule 6 — no "open" on any details element (TOC + FAQ collapsed)
if (/<details[^>]*\sopen[\s>]/i.test(html)) errors.push('Rule 6: found <details open> — all TOC/FAQ must start collapsed');

// Rule 4 — TOC anchor text must not start with "N."
const numberedToc = html.match(/<li[^>]*>\s*<a[^>]*>\s*\d+\s*[\.\)]/i);
if (numberedToc) errors.push('Rule 4: TOC contains a numeric prefix in the anchor text');

// Rule 18 — no dates in intro area (first 1800 chars, pre-TOC)
const preToc = html.split(/<details[^>]*class=[\"'][^\"']*pp-toc/)[0] || '';
if (/\b(19|20)\d{2}\b|\b(January|February|March|April|May|June|July|August|September|October|November|December)\b|\b(last|this|next)\s+(week|month|quarter|year)\b/i.test(preToc)) {
  warnings.push('Rule 18: possible date/time reference in intro area — review pre-TOC content');
}

// Rule 11 & 12 — floating buttons present
if (!/id=[\"']pp-float-contact[\"']/i.test(html)) errors.push('Rule 11: floating Contact Us button missing');
if (!/id=[\"']pp-float-top[\"']/i.test(html))     errors.push('Rule 12: floating Scroll-to-Top button missing');
if (!/window\.scrollY\s*>\s*300/.test(html) && !/scrollY > 300/.test(html)) warnings.push('Rule 12: scroll-top visibility threshold (300px) not detected');

// Rule 9 & 8 — CTAs to contact page
const contactHits = (html.match(new RegExp(brand.contactUrl.replace(/[.*+?^${}()|[\\]/g,'\\$&'),'gi')) || []).length;
if (contactHits < 4) warnings.push(`Rules 8/9/10: only ${contactHits} occurrences of ${brand.contactUrl} — expected 4+`);

// Rule 1, 2, 3 — About the Author integrity
if (!/PowerPlugLtd|powerplug-ltd/i.test(html)) errors.push('Rule 1: no real PowerPlug social URLs found');
if (!/href=[\"']https:\/\/powerplug\.ai[\"'][^>]*>[\s\S]{0,200}powerplug-logo/i.test(html)) warnings.push('Rule 2: verify the logo in the author block is wrapped in <a href="https://powerplug.ai">');

// Rule 13 — content blocks
const tipCount = (html.match(/class=[\"']pp-tip[\"']/gi) || []).length;
const howtoCount = (html.match(/class=[\"']pp-howto[\"']/gi) || []).length;
const didCount = (html.match(/class=[\"']pp-did[\"']/gi) || []).length;
if ((tipCount + howtoCount + didCount) < 3) errors.push(`Rule 13: only ${tipCount + howtoCount + didCount} Tip/How-To/Did-You-Know callouts — minimum 3`);

// Rule 15 — internal + external links
const internal = (html.match(/href=[\"']https?:\/\/powerplug\.ai[^\"']*[\"']/gi) || []).length;
const external = (html.match(/href=[\"']https?:\/\/(?!powerplug\.ai)[^\"']+[\"']/gi) || []).length;
if (internal < 2) errors.push(`Rule 15: ${internal} internal links — need at least 2`);
if (external < 2) errors.push(`Rule 15: ${external} external links — need at least 2`);

// Rule 16 — word count + placeholders
const text = html.replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();
const words = text.split(' ').filter(Boolean).length;
if (words < 1800) errors.push(`Rule 16: ~${words} words — under the 1,800 minimum`);
if (/lorem\s+ipsum|\[placeholder\]|TODO:/i.test(html)) errors.push('Rule 16: placeholder / Lorem Ipsum detected');

// Rule 20 — WordPress safety
if (/<!DOCTYPE|<html[\s>]|<head[\s>]|<body[\s>]/i.test(html)) errors.push('Rule 20/34: output must not include DOCTYPE/html/head/body');
if (/class=[\"'](?:[^\"']*\s)?(?:flex|grid-cols|bg-gradient|md:)/i.test(html)) warnings.push('Rule 20: possible Tailwind utility class detected — WordPress-safe inline styling preferred');

// Rule 23 — brand colors present
if (!html.includes(brand.colors.navyPrimary)) warnings.push(`Rule 23: ${brand.colors.navyPrimary} not present`);
if (!html.includes(brand.colors.greenAccent)) warnings.push(`Rule 23: ${brand.colors.greenAccent} not present`);

const passed = errors.length === 0;
const sizeBytes = new TextEncoder().encode(html).length;

return [{
  json: {
    html,
    validation: {
      passed,
      errors,
      warnings,
      stats: { h1Count, tipCount, howtoCount, didCount, internal, external, words, contactHits, sizeBytes }
    }
  }
}];
